(() => {
  'use strict';

  if (window.__pcbw_frontier_foundry_1_1_init) return;
  window.__pcbw_frontier_foundry_1_1_init = true;

  const CONFIG = {
    namespace: '__pcbw_ff_1_1',
    storageKey: '__pcbw_ff_1_1_state',
    schemaVersion: 1,
    maxEventHistory: 300,
    maxContextMessages: 5,
    world: {
      regionCount: 8,
      biomePool: ['storm-fens', 'ash-steppe', 'glasswood', 'ember-ridge', 'salt-basin', 'iron-marsh'],
      weatherPool: ['clear', 'fog', 'acid-drizzle', 'dust-storm', 'cold-front', 'electric-wind'],
      landmarkPool: ['collapsed relay', 'sunken observatory', 'fracture-gate', 'abandoned hydroforge', 'warding spire']
    },
    resources: {
      caps: {
        food: 180,
        water: 180,
        medicine: 40,
        salvage: 140,
        fuel: 90,
        relic: 30
      }
    }
  };

  const Utils = {
    nowIso() {
      return new Date().toISOString();
    },
    safeClone(value, fallback = null) {
      try {
        return JSON.parse(JSON.stringify(value));
      } catch (_err) {
        return fallback;
      }
    },
    clamp(value, min, max) {
      return Math.max(min, Math.min(max, value));
    },
    hash(input) {
      const text = String(input || '');
      let h = 2166136261;
      for (let i = 0; i < text.length; i++) {
        h ^= text.charCodeAt(i);
        h = Math.imul(h, 16777619);
      }
      return h >>> 0;
    },
    rng(seed) {
      let a = Utils.hash(seed);
      return function rand() {
        a += 0x6D2B79F5;
        let t = a;
        t = Math.imul(t ^ (t >>> 15), t | 1);
        t ^= t + Math.imul(t ^ (t >>> 7), t | 61);
        return ((t ^ (t >>> 14)) >>> 0) / 4294967296;
      };
    },
    pick(rand, list) {
      if (!Array.isArray(list) || !list.length) return null;
      return list[Math.floor(rand() * list.length) % list.length];
    },
    ensureContainers() {
      oc.character.customData ||= {};
      oc.character.customData.PUBLIC ||= {};
      oc.thread.customData ||= {};
    }
  };

  const WorldGen = {
    createSeed(seedHint) {
      if (seedHint && String(seedHint).trim()) {
        return String(seedHint).trim().toLowerCase();
      }
      const base = [
        String(Date.now()),
        String((oc.character && oc.character.name) || 'frontier-foundry'),
        String((oc.thread && oc.thread.messages && oc.thread.messages.length) || 0)
      ].join('|');
      return 'ff-' + Utils.hash(base).toString(36);
    },
    makeRegions(seed) {
      const rand = Utils.rng(seed + '|regions');
      const regions = [];
      for (let i = 0; i < CONFIG.world.regionCount; i++) {
        const id = 'rg-' + (i + 1);
        const biome = Utils.pick(rand, CONFIG.world.biomePool);
        const danger = Utils.clamp(Math.floor(rand() * 5) + 1, 1, 5);
        const resources = [
          Utils.pick(rand, ['food', 'water', 'medicine', 'salvage']),
          Utils.pick(rand, ['food', 'water', 'salvage', 'fuel', 'relic'])
        ].filter((value, idx, arr) => arr.indexOf(value) === idx);

        regions.push({
          id,
          name: 'Region ' + (i + 1),
          biome,
          danger,
          landmarks: [Utils.pick(rand, CONFIG.world.landmarkPool), Utils.pick(rand, CONFIG.world.landmarkPool)]
            .filter((value, idx, arr) => arr.indexOf(value) === idx),
          availableResources: resources,
          neighbors: []
        });
      }

      for (let i = 0; i < regions.length; i++) {
        const n1 = (i + 1) % regions.length;
        const n2 = (i + 2) % regions.length;
        const prev = (i - 1 + regions.length) % regions.length;
        regions[i].neighbors = [regions[n1].id, regions[n2].id, regions[prev].id]
          .filter((value, idx, arr) => arr.indexOf(value) === idx);
      }
      return regions;
    },
    makeWorld(seed) {
      const rand = Utils.rng(seed + '|world');
      const regions = WorldGen.makeRegions(seed);
      return {
        seed,
        regions,
        currentRegionId: regions[0].id,
        discoveredRegionIds: [regions[0].id],
        routeHistory: [regions[0].id],
        weather: {
          current: Utils.pick(rand, CONFIG.world.weatherPool),
          severity: Utils.clamp(Math.floor(rand() * 3) + 1, 1, 5)
        }
      };
    }
  };

  const FoundationModels = {
    makeParty(seed) {
      const rand = Utils.rng(seed + '|party');
      const names = ['Mara Quell', 'Torin Ash', 'Sera Vale', 'Iven Drax', 'Nyra Holt'];
      const roles = ['Pathfinder', 'Quartermaster', 'Medic', 'Engineer', 'Scout'];
      const members = Array.from({ length: 4 }).map((_, idx) => ({
        id: 'pm-' + (idx + 1),
        name: names[idx],
        role: roles[idx],
        morale: Utils.clamp(55 + Math.floor(rand() * 30), 0, 100),
        fatigue: Utils.clamp(10 + Math.floor(rand() * 20), 0, 100),
        status: 'ready'
      }));
      return {
        members,
        reserves: [],
        moraleAverage: 0,
        fatigueAverage: 0
      };
    },
    makeResources() {
      return {
        stock: {
          food: 110,
          water: 115,
          medicine: 18,
          salvage: 30,
          fuel: 20,
          relic: 0
        },
        caps: Utils.safeClone(CONFIG.resources.caps, {}),
        rates: {
          foodPerTurn: 3,
          waterPerTurn: 3,
          medicineChancePerTurn: 0.15
        }
      };
    },
    makeFactions(seed) {
      const rand = Utils.rng(seed + '|factions');
      const entries = [
        { id: 'river-compact', name: 'River Compact', doctrine: 'trade leverage' },
        { id: 'embersynod', name: 'Ember Synod', doctrine: 'knowledge custody' },
        { id: 'ironwardens', name: 'Iron Wardens', doctrine: 'security control' },
        { id: 'verdant-covenant', name: 'Verdant Covenant', doctrine: 'ecology restoration' }
      ];
      const state = {};
      for (const faction of entries) {
        state[faction.id] = {
          id: faction.id,
          name: faction.name,
          doctrine: faction.doctrine,
          reputation: Utils.clamp(Math.floor(rand() * 31) - 10, -100, 100),
          tension: Utils.clamp(Math.floor(rand() * 60), 0, 100),
          notes: []
        };
      }
      return state;
    },
    makeContracts(seed, world) {
      const rand = Utils.rng(seed + '|contracts');
      const regionA = world.regions[1] ? world.regions[1].id : world.currentRegionId;
      const regionB = world.regions[3] ? world.regions[3].id : world.currentRegionId;
      return {
        active: [
          {
            id: 'ct-1',
            title: 'Reopen the Foundry Relay',
            issuerFactionId: 'river-compact',
            objectiveType: 'recovery',
            regionId: regionA,
            objectives: [
              { id: 'ct-1-o1', text: 'Survey relay foundation', done: false },
              { id: 'ct-1-o2', text: 'Recover conductor core', done: false },
              { id: 'ct-1-o3', text: 'Restore beacon signal', done: false }
            ],
            deadlineDay: 7,
            risk: Utils.clamp(Math.floor(rand() * 5) + 1, 1, 5),
            rewards: { resources: { food: 16, water: 20, salvage: 14 }, reputation: { 'river-compact': 10 } },
            consequences: { reputation: { 'river-compact': -12 }, morale: -5 },
            progress: 0,
            status: 'active'
          }
        ],
        backlog: [
          {
            id: 'ct-2',
            title: 'Synod Archive Extraction',
            issuerFactionId: 'embersynod',
            objectiveType: 'intel',
            regionId: regionB,
            objectives: [
              { id: 'ct-2-o1', text: 'Secure archive chamber', done: false },
              { id: 'ct-2-o2', text: 'Extract ledger fragment', done: false }
            ],
            deadlineDay: 10,
            risk: Utils.clamp(Math.floor(rand() * 5) + 1, 1, 5),
            rewards: { resources: { medicine: 8, salvage: 12 }, reputation: { embersynod: 8 } },
            consequences: { reputation: { embersynod: -10 }, morale: -4 },
            progress: 0,
            status: 'available'
          }
        ],
        completed: [],
        failed: []
      };
    }
  };

  const StateSchema = {
    defaults(seedHint) {
      const seed = WorldGen.createSeed(seedHint);
      const world = WorldGen.makeWorld(seed);
      const party = FoundationModels.makeParty(seed);

      return {
        schemaVersion: CONFIG.schemaVersion,
        expedition: {
          id: 'exp-' + Date.now(),
          name: 'Chronicle Foundry Expedition',
          status: 'active',
          seed,
          startedAt: Utils.nowIso(),
          notes: ''
        },
        world,
        time: {
          day: 1,
          hour: 7,
          turn: 0,
          phase: 'dawn',
          totalHoursElapsed: 0
        },
        resources: FoundationModels.makeResources(),
        party,
        factions: FoundationModels.makeFactions(seed),
        contracts: FoundationModels.makeContracts(seed, world),
        events: {
          history: [],
          counters: {
            travel: 0,
            camp: 0,
            command: 0
          }
        },
        ui: {
          appReady: false,
          screen: 'dashboard',
          debug: false
        },
        system: {
          lastSavedAt: Utils.nowIso(),
          lastLoadedAt: Utils.nowIso(),
          contextMessageIds: []
        }
      };
    }
  };

  const Migrations = {
    apply(rawState) {
      if (!rawState || typeof rawState !== 'object') return null;
      const state = rawState;
      state.schemaVersion ||= 0;

      if (state.schemaVersion < 1) {
        state.events ||= { history: [], counters: { travel: 0, camp: 0, command: 0 } };
        state.system ||= { lastSavedAt: Utils.nowIso(), lastLoadedAt: Utils.nowIso(), contextMessageIds: [] };
        state.schemaVersion = 1;
      }

      state.schemaVersion = CONFIG.schemaVersion;
      return state;
    }
  };

  const Storage = {
    read() {
      Utils.ensureContainers();
      const ns = CONFIG.namespace;
      const key = CONFIG.storageKey;
      const candidates = [
        oc.thread.customData[ns],
        oc.character.customData[ns],
        oc.character.customData.PUBLIC[key]
      ];

      for (const candidate of candidates) {
        if (!candidate) continue;
        const cloned = Utils.safeClone(candidate, null);
        if (!cloned) continue;
        const migrated = Migrations.apply(cloned);
        if (!Engine.validateShape(migrated)) continue;
        migrated.system.lastLoadedAt = Utils.nowIso();
        return migrated;
      }

      return StateSchema.defaults();
    },
    write(state) {
      Utils.ensureContainers();
      const serial = Utils.safeClone(state, null);
      if (!serial) return;
      serial.system.lastSavedAt = Utils.nowIso();
      oc.thread.customData[CONFIG.namespace] = serial;
      oc.character.customData[CONFIG.namespace] = serial;
      oc.character.customData.PUBLIC[CONFIG.storageKey] = serial;
    }
  };

  const EventLog = {
    add(type, detail) {
      const state = Engine.state;
      const row = {
        id: 'ev-' + Date.now() + '-' + Math.floor(Math.random() * 100000),
        at: Utils.nowIso(),
        turn: state.time.turn,
        type,
        detail: String(detail || '').slice(0, 600)
      };
      state.events.history.push(row);
      state.events.history = state.events.history.slice(-CONFIG.maxEventHistory);
      return row;
    },
    summarizeRecent(limit = 5) {
      const rows = Engine.state.events.history.slice(-limit);
      if (!rows.length) return 'No notable events logged yet.';
      return rows.map((row) => '- T' + row.turn + ' [' + row.type + '] ' + row.detail).join('\\n');
    }
  };

  const ContextBuilder = {
    build() {
      const state = Engine.state;
      const worldRegion = Engine.getCurrentRegion();
      const lowResources = [];
      for (const key of ['food', 'water', 'medicine']) {
        const current = state.resources.stock[key] || 0;
        const cap = state.resources.caps[key] || 1;
        if (current / cap < 0.2) lowResources.push(key + ':' + current);
      }

      const activeContracts = state.contracts.active.map((c) => c.title + ' (D' + c.deadlineDay + ', ' + c.regionId + ')');
      const topFaction = Object.values(state.factions)
        .sort((a, b) => b.reputation - a.reputation)[0];

      return [
        'Expedition Context v' + state.schemaVersion,
        'Seed: ' + state.expedition.seed,
        'Time: day ' + state.time.day + ', hour ' + state.time.hour + ', turn ' + state.time.turn,
        'Region: ' + (worldRegion ? worldRegion.name : state.world.currentRegionId),
        'Weather: ' + state.world.weather.current + ' (severity ' + state.world.weather.severity + ')',
        'Resources: food ' + state.resources.stock.food + ', water ' + state.resources.stock.water + ', medicine ' + state.resources.stock.medicine + ', salvage ' + state.resources.stock.salvage + ', fuel ' + state.resources.stock.fuel,
        'Party morale/fatigue avg: ' + state.party.moraleAverage + '/' + state.party.fatigueAverage,
        'Top faction: ' + (topFaction ? topFaction.name + ' rep ' + topFaction.reputation : 'none'),
        'Active contracts: ' + (activeContracts.length ? activeContracts.join('; ') : 'none'),
        'Low resource alerts: ' + (lowResources.length ? lowResources.join(', ') : 'none'),
        'Recent events:\\n' + EventLog.summarizeRecent(4)
      ].join('\n');
    },
    injectHiddenSystemContext() {
      const content = ContextBuilder.build();
      const msg = {
        author: 'system',
        content,
        hiddenFrom: ['user'],
        expectsReply: false,
        customData: {
          __pcbw_ff_context: true,
          createdAt: Utils.nowIso()
        }
      };
      oc.thread.messages.push(msg);
      const history = Engine.state.system.contextMessageIds;
      history.push(msg.customData.createdAt);
      if (history.length > CONFIG.maxContextMessages) history.splice(0, history.length - CONFIG.maxContextMessages);
      ContextBuilder.pruneOldContextMessages();
    },
    pruneOldContextMessages() {
      const indexes = [];
      for (let i = 0; i < oc.thread.messages.length; i++) {
        const m = oc.thread.messages[i];
        if (m && m.author === 'system' && m.customData && m.customData.__pcbw_ff_context === true) {
          indexes.push(i);
        }
      }
      const removeCount = Math.max(0, indexes.length - CONFIG.maxContextMessages);
      for (let i = 0; i < removeCount; i++) {
        const idx = indexes[i] - i;
        oc.thread.messages.splice(idx, 1);
      }
    }
  };

  const Commands = {
    helpText() {
      return [
        'Frontier Foundry Commands:',
        '!help - command list',
        '!status - expedition status snapshot',
        '!travel <region-id> - move to neighboring region',
        '!camp - perform camp turn and recover',
        '!new-expedition [seed] - reset into fresh deterministic world seed',
        '!reset - safety reset using current seed',
        '!diagnostics - engine diagnostics block'
      ].join('\n');
    },
    parse(input) {
      const text = String(input || '').trim();
      if (!text.startsWith('!')) return null;
      const parts = text.slice(1).trim().split(/\s+/).filter(Boolean);
      if (!parts.length) return null;
      return {
        command: parts[0].toLowerCase(),
        args: parts.slice(1),
        raw: text
      };
    }
  };

  const ActionHandlers = {
    systemNotice(text) {
      oc.thread.messages.push({
        author: 'system',
        content: String(text || ''),
        expectsReply: false
      });
    },
    status() {
      const state = Engine.state;
      const region = Engine.getCurrentRegion();
      const text = [
        'SITREP — Foundation Engine',
        'Expedition: ' + state.expedition.name,
        'Seed: ' + state.expedition.seed,
        'Time: day ' + state.time.day + ', hour ' + state.time.hour + ', turn ' + state.time.turn,
        'Region: ' + (region ? region.name + ' [' + region.id + ']' : state.world.currentRegionId),
        'Weather: ' + state.world.weather.current + ' (sev ' + state.world.weather.severity + ')',
        'Resources: food ' + state.resources.stock.food + ', water ' + state.resources.stock.water + ', med ' + state.resources.stock.medicine + ', salvage ' + state.resources.stock.salvage + ', fuel ' + state.resources.stock.fuel,
        'Active contracts: ' + state.contracts.active.length,
        'Recent event: ' + (state.events.history.length ? state.events.history[state.events.history.length - 1].detail : 'none')
      ].join('\n');
      ActionHandlers.systemNotice(text);
    },
    advanceTime(hours) {
      const state = Engine.state;
      state.time.totalHoursElapsed += hours;
      state.time.hour += hours;
      while (state.time.hour >= 24) {
        state.time.hour -= 24;
        state.time.day += 1;
      }
      state.time.turn += 1;
      if (state.time.hour < 5) state.time.phase = 'deep-night';
      else if (state.time.hour < 8) state.time.phase = 'dawn';
      else if (state.time.hour < 12) state.time.phase = 'morning';
      else if (state.time.hour < 17) state.time.phase = 'afternoon';
      else if (state.time.hour < 20) state.time.phase = 'dusk';
      else state.time.phase = 'night';
    },
    consumeResources() {
      const state = Engine.state;
      state.resources.stock.food = Utils.clamp(state.resources.stock.food - state.resources.rates.foodPerTurn, 0, state.resources.caps.food);
      state.resources.stock.water = Utils.clamp(state.resources.stock.water - state.resources.rates.waterPerTurn, 0, state.resources.caps.water);
      if (Math.random() < state.resources.rates.medicineChancePerTurn) {
        state.resources.stock.medicine = Utils.clamp(state.resources.stock.medicine - 1, 0, state.resources.caps.medicine);
      }
    },
    recomputePartyMetrics() {
      const members = Engine.state.party.members;
      if (!members.length) {
        Engine.state.party.moraleAverage = 0;
        Engine.state.party.fatigueAverage = 0;
        return;
      }
      const morale = members.reduce((acc, m) => acc + m.morale, 0) / members.length;
      const fatigue = members.reduce((acc, m) => acc + m.fatigue, 0) / members.length;
      Engine.state.party.moraleAverage = Math.round(morale);
      Engine.state.party.fatigueAverage = Math.round(fatigue);
    },
    travel(targetRegionId) {
      const state = Engine.state;
      const current = Engine.getCurrentRegion();
      if (!targetRegionId) {
        ActionHandlers.systemNotice('Travel failed: include a target region id, e.g. !travel rg-2');
        return;
      }
      if (!current || !current.neighbors.includes(targetRegionId)) {
        ActionHandlers.systemNotice('Travel failed: target is not adjacent. Adjacent: ' + (current ? current.neighbors.join(', ') : 'none'));
        return;
      }
      state.world.currentRegionId = targetRegionId;
      if (!state.world.discoveredRegionIds.includes(targetRegionId)) {
        state.world.discoveredRegionIds.push(targetRegionId);
      }
      state.world.routeHistory.push(targetRegionId);
      ActionHandlers.advanceTime(6);
      ActionHandlers.consumeResources();
      const rand = Utils.rng(state.expedition.seed + '|travel|' + state.time.turn);
      state.world.weather.current = Utils.pick(rand, CONFIG.world.weatherPool);
      state.world.weather.severity = Utils.clamp(Math.floor(rand() * 5) + 1, 1, 5);
      EventLog.add('travel', 'Moved expedition from ' + current.id + ' to ' + targetRegionId + '.');
      ActionHandlers.recomputePartyMetrics();
      ActionHandlers.status();
    },
    camp() {
      const state = Engine.state;
      ActionHandlers.advanceTime(8);
      ActionHandlers.consumeResources();
      for (const member of state.party.members) {
        member.fatigue = Utils.clamp(member.fatigue - 10, 0, 100);
        member.morale = Utils.clamp(member.morale + 3, 0, 100);
      }
      ActionHandlers.recomputePartyMetrics();
      EventLog.add('camp', 'Established camp and executed recovery cycle.');
      ActionHandlers.systemNotice('Camp turn completed. Party recovered and supplies adjusted.');
      ActionHandlers.status();
    },
    newExpedition(seedHint) {
      const next = StateSchema.defaults(seedHint);
      Engine.state = next;
      EventLog.add('system', 'Started new expedition with seed ' + Engine.state.expedition.seed + '.');
      ActionHandlers.systemNotice('New expedition initialized with deterministic seed: ' + Engine.state.expedition.seed);
      ActionHandlers.status();
    },
    reset() {
      ActionHandlers.newExpedition(Engine.state.expedition.seed);
      EventLog.add('system', 'Safety reset completed for current seed.');
      ActionHandlers.systemNotice('Safety reset complete. Seed preserved: ' + Engine.state.expedition.seed);
    },
    diagnostics() {
      const state = Engine.state;
      const payload = {
        schemaVersion: state.schemaVersion,
        seed: state.expedition.seed,
        currentRegionId: state.world.currentRegionId,
        turn: state.time.turn,
        events: state.events.history.length,
        discoveredRegions: state.world.discoveredRegionIds.length,
        activeContracts: state.contracts.active.length,
        contextMessagesTracked: state.system.contextMessageIds.length,
        storageNamespace: CONFIG.namespace
      };
      ActionHandlers.systemNotice('<pre>' + JSON.stringify(payload, null, 2) + '</pre>');
    }
  };

  const ReleaseDebug = {
    applyShortcuts() {
      oc.thread.shortcutButtons = [
        { name: 'Help', message: '!help', insertionType: 'replace', autoSend: true, clearAfterSend: true },
        { name: 'Status', message: '!status', insertionType: 'replace', autoSend: true, clearAfterSend: true },
        { name: 'Camp', message: '!camp', insertionType: 'replace', autoSend: true, clearAfterSend: true },
        { name: 'Travel rg-2', message: '!travel rg-2', insertionType: 'replace', autoSend: true, clearAfterSend: true },
        { name: 'New Expedition', message: '!new-expedition', insertionType: 'replace', autoSend: true, clearAfterSend: true }
      ];
    },
    syncReminder() {
      const state = Engine.state;
      const region = Engine.getCurrentRegion();
      oc.character.reminderMessage = [
        'State-locked expedition engine active.',
        'Seed: ' + state.expedition.seed + '. Day ' + state.time.day + ', hour ' + state.time.hour + ', turn ' + state.time.turn + '.',
        'Region: ' + (region ? region.name + ' (' + region.id + ')' : state.world.currentRegionId) + '.',
        'Keep continuity with resources, party strain, faction reputation, contract deadlines, and event log.',
        'Use concise SITREP first, then narrative progression, then actions.'
      ].join(' ');
    }
  };

  const Engine = {
    state: null,
    validateShape(state) {
      if (!state || typeof state !== 'object') return false;
      if (!state.world || !Array.isArray(state.world.regions)) return false;
      if (!state.resources || !state.resources.stock || !state.resources.caps) return false;
      if (!state.party || !Array.isArray(state.party.members)) return false;
      if (!state.factions || typeof state.factions !== 'object') return false;
      if (!state.contracts || !Array.isArray(state.contracts.active)) return false;
      if (!state.events || !Array.isArray(state.events.history)) return false;
      return true;
    },
    getCurrentRegion() {
      return Engine.state.world.regions.find((r) => r.id === Engine.state.world.currentRegionId) || null;
    },
    bootstrap() {
      Engine.state = Storage.read();
      ActionHandlers.recomputePartyMetrics();
      if (!Engine.state.events.history.length) {
        EventLog.add('system', 'Phase 1 foundation boot complete.');
      }
      ReleaseDebug.applyShortcuts();
      ReleaseDebug.syncReminder();
      Storage.write(Engine.state);
    },
    handleCommand(parsed) {
      if (!parsed) return false;
      Engine.state.events.counters.command += 1;
      const command = parsed.command;
      if (command === 'help') {
        ActionHandlers.systemNotice(Commands.helpText());
        EventLog.add('command', 'Displayed help command output.');
      } else if (command === 'status') {
        ActionHandlers.status();
        EventLog.add('command', 'Displayed status snapshot.');
      } else if (command === 'travel') {
        ActionHandlers.travel(parsed.args[0]);
      } else if (command === 'camp') {
        ActionHandlers.camp();
      } else if (command === 'new-expedition') {
        ActionHandlers.newExpedition(parsed.args[0]);
      } else if (command === 'reset') {
        ActionHandlers.reset();
      } else if (command === 'diagnostics') {
        ActionHandlers.diagnostics();
        EventLog.add('command', 'Displayed diagnostics payload.');
      } else {
        ActionHandlers.systemNotice('Unknown command: ' + parsed.raw + '\\nUse !help for available commands.');
      }

      ReleaseDebug.syncReminder();
      Storage.write(Engine.state);
      return true;
    }
  };

  Engine.bootstrap();

  oc.thread.on('MessageAdded', ({ message }) => {
    if (!message) return;
    if (message.author !== 'user') return;

    const parsed = Commands.parse(message.content);
    if (parsed) {
      const idx = oc.thread.messages.indexOf(message);
      if (idx >= 0) oc.thread.messages.splice(idx, 1);
      Engine.handleCommand(parsed);
      return;
    }

    ContextBuilder.injectHiddenSystemContext();
    ReleaseDebug.syncReminder();
    Storage.write(Engine.state);
  });
})();
